/**
 * @method
 * @name bitmex#fetchMyTrades
 * @description fetch all trades made by the user
 * @see https://www.bitmex.com/api/explorer/#!/Execution/Execution_getTradeHistory
 * @param {string} symbol unified market symbol
 * @param {int} [since] the earliest time in ms to fetch trades for
 * @param {int} [limit] the maximum number of trades structures to retrieve
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @param {boolean} [params.paginate] default false, when true will automatically paginate by calling this endpoint multiple times. See in the docs all the [availble parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-params)
 * @returns {Trade[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=trade-structure}
 */
func (this *BitmexCore) FetchMyTrades(optionalArgs ...any) <-chan any {
	ch := make(chan any)
	go func() any {
		defer close(ch)
		defer ReturnPanicError(ch)
		symbol := GetArg(optionalArgs, 0, nil)
		_ = symbol
		since := GetArg(optionalArgs, 1, nil)
		_ = since
		limit := GetArg(optionalArgs, 2, nil)
		_ = limit
		params := GetArg(optionalArgs, 3, map[string]any{})
		_ = params

		retRes11568 := (<-this.LoadMarkets())
		PanicOnError(retRes11568)
		var paginate any = false
		paginateparamsVariable := this.HandleOptionAndParams(params, "fetchMyTrades", "paginate")
		paginate = GetValue(paginateparamsVariable, 0)
		params = GetValue(paginateparamsVariable, 1)
		if IsTrue(paginate) {

			retRes116019 := (<-this.FetchPaginatedCallDynamic("fetchMyTrades", symbol, since, limit, params, 100))
			PanicOnError(retRes116019)
			ch <- retRes116019
			return nil
		}
		var market any = nil
		var request any = map[string]any{}
		if IsTrue(!IsEqual(symbol, nil)) {
			market = this.Market(symbol)
			AddElementToObject(request, "symbol", GetValue(market, "id"))
		}
		if IsTrue(!IsEqual(since, nil)) {
			AddElementToObject(request, "startTime", this.Iso8601(since))
		}
		if IsTrue(!IsEqual(limit, nil)) {
			AddElementToObject(request, "count", mathMin(500, limit))
		}
		var until any = this.SafeInteger2(params, "until", "endTime")
		if IsTrue(!IsEqual(until, nil)) {
			params = this.Omit(params, []any{"until"})
			AddElementToObject(request, "endTime", this.Iso8601(until))
		}
		request = this.DeepExtend(request, params)
		// why the hassle? urlencode in python is kinda broken for nested dicts.
		// E.g. self.urlencode({"filter": {"open": True}}) will return "filter={'open':+True}"
		// Bitmex doesn't like that. Hence resorting to this hack.
		if IsTrue(InOp(request, "filter")) {
			AddElementToObject(request, "filter", this.Json(GetValue(request, "filter")))
		}

		response := (<-this.PrivateGetExecutionTradeHistory(request))
		PanicOnError(response)

		//
		//     [
		//         {
		//             "execID": "string",
		//             "orderID": "string",
		//             "clOrdID": "string",
		//             "clOrdLinkID": "string",
		//             "account": 0,
		//             "symbol": "string",
		//             "side": "string",
		//             "lastQty": 0,
		//             "lastPx": 0,
		//             "underlyingLastPx": 0,
		//             "lastMkt": "string",
		//             "lastLiquidityInd": "string",
		//             "simpleOrderQty": 0,
		//             "orderQty": 0,
		//             "price": 0,
		//             "displayQty": 0,
		//             "stopPx": 0,
		//             "pegOffsetValue": 0,
		//             "pegPriceType": "string",
		//             "currency": "string",
		//             "settlCurrency": "string",
		//             "execType": "string",
		//             "ordType": "string",
		//             "timeInForce": "string",
		//             "execInst": "string",
		//             "contingencyType": "string",
		//             "exDestination": "string",
		//             "ordStatus": "string",
		//             "triggered": "string",
		//             "workingIndicator": true,
		//             "ordRejReason": "string",
		//             "simpleLeavesQty": 0,
		//             "leavesQty": 0,
		//             "simpleCumQty": 0,
		//             "cumQty": 0,
		//             "avgPx": 0,
		//             "commission": 0,
		//             "tradePublishIndicator": "string",
		//             "multiLegReportingType": "string",
		//             "text": "string",
		//             "trdMatchID": "string",
		//             "execCost": 0,
		//             "execComm": 0,
		//             "homeNotional": 0,
		//             "foreignNotional": 0,
		//             "transactTime": "2019-03-05T12:47:02.762Z",
		//             "timestamp": "2019-03-05T12:47:02.762Z"
		//         }
		//     ]
		//
		ch <- this.ParseTrades(response, market, since, limit)
		return nil

	}()
	return ch
}
func (this *BitmexCore) ParseLedgerEntryType(typeVar any) any {
	var types any = map[string]any{
		"Withdrawal":      "transaction",
		"RealisedPNL":     "margin",
		"UnrealisedPNL":   "margin",
		"Deposit":         "transaction",
		"Transfer":        "transfer",
		"AffiliatePayout": "referral",
		"SpotTrade":       "trade",
	}
	return this.SafeString(types, typeVar, typeVar)
}
func (this *BitmexCore) ParseLedgerEntry(item any, optionalArgs ...any) any {
	//
	//     {
	//         "transactID": "69573da3-7744-5467-3207-89fd6efe7a47",
	//         "account":  24321,
	//         "currency": "XBt",
	//         "transactType": "Withdrawal", // "AffiliatePayout", "Transfer", "Deposit", "RealisedPNL", ...
	//         "amount":  -1000000,
	//         "fee":  300000,
	//         "transactStatus": "Completed", // "Canceled", ...
	//         "address": "1Ex4fkF4NhQaQdRWNoYpqiPbDBbq18Kdd9",
	//         "tx": "3BMEX91ZhhKoWtsH9QRb5dNXnmnGpiEetA",
	//         "text": "",
	//         "transactTime": "2017-03-21T20:05:14.388Z",
	//         "walletBalance":  0, // balance after
	//         "marginBalance":  null,
	//         "timestamp": "2017-03-22T13:09:23.514Z"
	//     }
	//
	// ButMEX returns the unrealized pnl from the wallet history endpoint.
	// The unrealized pnl transaction has an empty timestamp.
	// It is not related to historical pnl it has status set to "Pending".
	// Therefore it's not a part of the history at all.
	// https://github.com/ccxt/ccxt/issues/6047
	//
	//     {
	//         "transactID":"00000000-0000-0000-0000-000000000000",
	//         "account":121210,
	//         "currency":"XBt",
	//         "transactType":"UnrealisedPNL",
	//         "amount":-5508,
	//         "fee":0,
	//         "transactStatus":"Pending",
	//         "address":"XBTUSD",
	//         "tx":"",
	//         "text":"",
	//         "transactTime":null,  # ←---------------------------- null
	//         "walletBalance":139198767,
	//         "marginBalance":139193259,
	//         "timestamp":null  # ←---------------------------- null
	//     }
	//
	currency := GetArg(optionalArgs, 0, nil)
	_ = currency
	var id any = this.SafeString(item, "transactID")
	var account any = this.SafeString(item, "account")
	var referenceId any = this.SafeString(item, "tx")
	var referenceAccount any = nil
	var typeVar any = this.ParseLedgerEntryType(this.SafeString(item, "transactType"))
	var currencyId any = this.SafeString(item, "currency")
	var code any = this.SafeCurrencyCode(currencyId, currency)
	currency = this.SafeCurrency(currencyId, currency)
	var amountString any = this.SafeString(item, "amount")
	var amount any = this.ConvertToRealAmount(code, amountString)
	var timestamp any = this.Parse8601(this.SafeString(item, "transactTime"))
	if IsTrue(IsEqual(timestamp, nil)) {
		// https://github.com/ccxt/ccxt/issues/6047
		// set the timestamp to zero, 1970 Jan 1 00:00:00
		// for unrealized pnl and other transactions without a timestamp
		timestamp = 0 // see comments above
	}
	var fee any = nil
	var feeCost any = this.SafeString(item, "fee")
	if IsTrue(!IsEqual(feeCost, nil)) {
		feeCost = this.ConvertToRealAmount(code, feeCost)
		fee = map[string]any{
			"cost":     this.ParseNumber(feeCost),
			"currency": code,
		}
	}
	var after any = this.SafeString(item, "walletBalance")
	if IsTrue(!IsEqual(after, nil)) {
		after = this.ConvertToRealAmount(code, after)
	}
	var before any = this.ParseNumber(Precise.StringSub(this.NumberToString(after), this.NumberToString(amount)))
	var direction any = nil
	if IsTrue(Precise.StringLt(amountString, "0")) {
		direction = "out"
		amount = this.ConvertToRealAmount(code, Precise.StringAbs(amountString))
	} else {
		direction = "in"
	}
	var status any = this.ParseTransactionStatus(this.SafeString(item, "transactStatus"))
	return this.SafeLedgerEntry(map[string]any{
		"info":             item,
		"id":               id,
		"timestamp":        timestamp,
		"datetime":         this.Iso8601(timestamp),
		"direction":        direction,
		"account":          account,
		"referenceId":      referenceId,
		"referenceAccount": referenceAccount,
		"type":             typeVar,
		"currency":         code,
		"amount":           this.ParseNumber(amount),
		"before":           before,
		"after":            this.ParseNumber(after),
		"status":           status,
		"fee":              fee,
	}, currency)
}

